import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.D4v4AkDZ.js";const r="/english-quest-log/assets/clase2past.Ci_n7eU4.png",n="/english-quest-log/assets/clase2th.BKhZIxMq.png",g=JSON.parse('{"title":"📝 Clase 02 — Tenses Overview + Present Perfect","description":"Tiempos verbales — auxiliares y Present Perfect","frontmatter":{"title":"📝 Clase 02 — Tenses Overview + Present Perfect","date":"2026-03-11T00:00:00.000Z","description":"Tiempos verbales — auxiliares y Present Perfect","level":"B2"},"headers":[],"relativePath":"clases/clase-02.md","filePath":"clases/clase-02.md","lastUpdated":1773231589000}'),i={name:"clases/clase-02.md"};function l(d,e,c,u,p,h){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="📝-clase-02-—-tenses-overview-present-perfect" tabindex="-1">📝 Clase 02 — Tenses Overview + Present Perfect <a class="header-anchor" href="#📝-clase-02-—-tenses-overview-present-perfect" aria-label="Permalink to &quot;📝 Clase 02 — Tenses Overview + Present Perfect&quot;">​</a></h1><p><strong>Fecha:</strong> 2026-02-xx <strong>Tema:</strong> Tiempos verbales — auxiliares y Present Perfect <strong>Nivel:</strong> B2</p><p><img src="'+r+'" alt="Past Simple - referencia"><img src="'+n+'" alt="TH pronunciation - referencia"></p><hr><h2 id="🗺️-mapa-de-tiempos-verbales" tabindex="-1">🗺️ Mapa de tiempos verbales <a class="header-anchor" href="#🗺️-mapa-de-tiempos-verbales" aria-label="Permalink to &quot;🗺️ Mapa de tiempos verbales&quot;">​</a></h2><p>Un resumen rápido de los <strong>auxiliares</strong> por tiempo:</p><table tabindex="0"><thead><tr><th>Tiempo</th><th>Auxiliar</th><th>Ejemplo</th></tr></thead><tbody><tr><td><strong>Past Simple</strong></td><td><code>did</code> (negación / preguntas)</td><td><em>Did you go? / I didn&#39;t go.</em></td></tr><tr><td><strong>Present</strong></td><td><code>do / does</code></td><td><em>Do you work here?</em></td></tr><tr><td><strong>Present Perfect</strong></td><td><code>have / has</code></td><td><em>I have visited Paris.</em></td></tr><tr><td><strong>Future</strong></td><td><code>will</code></td><td><em>I will travel next year.</em></td></tr></tbody></table><hr><h2 id="⏱️-present-perfect" tabindex="-1">⏱️ Present Perfect <a class="header-anchor" href="#⏱️-present-perfect" aria-label="Permalink to &quot;⏱️ Present Perfect&quot;">​</a></h2><p><strong>Auxiliar:</strong> <code>have</code> / <code>has</code></p><p>Se usa para:</p><ul><li>Experiencias de vida (sin tiempo específico)</li><li>Acciones que conectan el pasado con el presente</li></ul><blockquote><p><em>I <strong>have</strong> eaten sushi.</em> → en algún momento de mi vida vs. <em>I <strong>ate</strong> sushi yesterday.</em> → momento específico → Past Simple ✅</p></blockquote><h3 id="estructura" tabindex="-1">Estructura <a class="header-anchor" href="#estructura" aria-label="Permalink to &quot;Estructura&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Sujeto</th><th>Auxiliar</th><th>Participio pasado</th></tr></thead><tbody><tr><td>I / You / We / They</td><td><strong>have</strong></td><td>visited / eaten / gone</td></tr><tr><td>He / She / It</td><td><strong>has</strong></td><td>visited / eaten / gone</td></tr></tbody></table><hr><h2 id="🔊-tips-de-pronunciacion" tabindex="-1">🔊 Tips de pronunciación <a class="header-anchor" href="#🔊-tips-de-pronunciacion" aria-label="Permalink to &quot;🔊 Tips de pronunciación&quot;">​</a></h2><h3 id="la-i-vs-y-—-¡lo-opuesto-al-espanol" tabindex="-1">La &quot;I&quot; vs &quot;Y&quot; — ¡lo opuesto al español! <a class="header-anchor" href="#la-i-vs-y-—-¡lo-opuesto-al-espanol" aria-label="Permalink to &quot;La &quot;I&quot; vs &quot;Y&quot; — ¡lo opuesto al español!&quot;">​</a></h3><p>En español, <strong>i</strong> e <strong>y</strong> suenan igual (i latina). En inglés es casi al revés:</p><ul><li><strong>&quot;i&quot;</strong> en inglés suena como la <strong>&quot;ai&quot;</strong> del español → <em>like</em>, <em>night</em>, <em>I</em></li><li><strong>&quot;y&quot;</strong> al inicio de palabra suena como la <strong>&quot;ll/y&quot;</strong> del español → <em>yes</em>, <em>you</em>, <em>year</em></li></ul><blockquote><p>Ejemplo: <strong>&quot;I&quot;</strong> (yo) se pronuncia <strong>&quot;ai&quot;</strong>, no &quot;i&quot;.</p></blockquote><hr><h2 id="🔗-recursos" tabindex="-1">🔗 Recursos <a class="header-anchor" href="#🔗-recursos" aria-label="Permalink to &quot;🔗 Recursos&quot;">​</a></h2><ul><li>Imágenes de referencia en esta carpeta (<code>clase2past.png</code>, <code>clase2th.png</code>)</li></ul>',24)])])}const q=t(i,[["render",l]]);export{g as __pageData,q as default};
